 * Searches for users by email in PostgreSQL.
 * @param {string} searchTerm The term to search for in user emails.
 * @returns {Promise<Array>} A promise that resolves with an array of matching users.
 */
async function searchUsers(searchTerm) {
  const client = await pool.connect();
  try {
    // Use a parameterized query to prevent SQL injection.
    // The ILIKE keyword is used for case-insensitive matching.
    const query = 'SELECT * FROM users WHERE email ILIKE $1';
    const values = [`%${searchTerm}%`];
    const res = await client.query(query, values);
    return res.rows;
  } catch (err) {
    console.error('Error searching for users:', err);
    throw err;
  } finally {
    client.release();
  }
}

