});

/**
 * Updates a user's profile in the PostgreSQL database.
 *
 * @param {number | string} userId - The ID of the user to update.
 * @param {object} profileData - An object where keys are column names and values are the new data.
 * @returns {Promise<object>} A promise that resolves to the updated user object.
 * @throws {Error} Throws an error if the update fails or no user is found.
 */
async function updateUserProfile(userId, profileData) {
  const keys = Object.keys(profileData);
  if (keys.length === 0) {
    throw new Error('profileData object cannot be empty.');
  }

  // Dynamically construct the SET part of the query
  const setClause = keys.map((key, index) => `"${key}" = $${index + 2}`).join(', ');
  const values = [userId, ...Object.values(profileData)];

  const query = {
    text: `UPDATE users SET ${setClause} WHERE id = $1 RETURNING *;`,
    values: values,
  };

  const client = await pool.connect();
  try {
    const res = await client.query(query);
    if (res.rows.length === 0) {
      throw new Error(`User with ID ${userId} not found.`);
    }
    return res.rows[0];
  } catch (err) {
    // Re-throw the error to be handled by the caller
    throw err;
  } finally {
    client.release();
  }
}

