    let encryptedData = cipher.update(plaintext, 'utf8', 'hex');
    encryptedData += cipher.final('hex');

    // 4. Get the authentication tag
    const authTag = cipher.getAuthTag();

    // 5. Combine IV, auth tag, and encrypted data for storage or transmission.
    // The format is "iv:authTag:encryptedData", all hex-encoded.
    return `${iv.toString('hex')}:${authTag.toString('hex')}:${encryptedData}`;
